class Solution:
    def prefixCount(self, words, pref):
        L = len(pref)
        total = 0
        for w in words:
            if len(w) >= L and w[:L] == pref:
                total += 1
        return total

solutions.python:
class Solution:
    def prefixCount(self, words, pref):
        return sum(1 for w in words if w.startswith(pref))

